#include <bits/stdc++.h>
using namespace std;

struct Milk {
    int p, a;
} milk[5005];

bool cmp(Milk a, Milk b) {
    return a.p < b.p;
}

int main() {
    int n, m, i = 0, ans = 0;
    cin >> n >> m;
    for (int i = 0; i < m; i++) {
        cin >> milk[i].p >> milk[i].a;
    }
    sort(milk, milk + m, cmp);
    while (true) {
        if (n <= milk[i].a) {
            ans += n * milk[i].p;
            break;
        }
        else {
            ans += milk[i].p * milk[i].a;
            n -= milk[i].a;
            i++;
        }
    }
    cout << ans << endl;
    return 0;
}
